  function decodeVapidKey(value: string) { const padding = '='.repeat((4 - value.length % 4) % 4); const normalized = (value + padding).replaceAll('-', '+').replaceAll('_', '/'); return Uint8Array.from(atob(normalized), (char) => char.charCodeAt(0)); }
  async function refreshPushState() {
    pushAvailable = typeof window !== 'undefined' && 'serviceWorker' in navigator && 'PushManager' in window && 'Notification' in window;
    if (!pushAvailable || !authUser) return;
    try { const result = await request('/api/v1/notifications/config'); vapidPublicKey = result.body?.vapid_public_key ?? ''; } catch { vapidPublicKey = ''; }
