  async function persistDraft(channel: string, body: string) {
    try {
      const url = `/api/v1/drafts/${encodeURIComponent(channel)}`;
      if (body.trim()) await request(url, { method: 'PUT', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ body }) });
      else await request(url, { method: 'DELETE', headers: { 'x-csrf-token': csrf } });
    } catch { /* draft persistence is best effort while offline */ }
  }
  function scheduleDraftSave() {
