    } catch { if (activeChannel === channel) draft = ''; }
  }
  async function readNotification(notification: Notification) { try { await request(`/api/v1/notifications/${notification.id}/read`, { method: 'POST', headers: { 'x-csrf-token': csrf } }); notifications = notifications.map((item) => item.id === notification.id ? { ...item, read_at: Date.now() } : item); } catch { /* keep notification unread */ } }
  function searchUrl(cursor?: { before_created_at: number; before_id: string }) { const params = new URLSearchParams({ q: messageSearch.trim(), limit: '20' }); if (searchChannel) params.set('channel', searchChannel); if (searchFrom) params.set('from', String(Date.parse(`${searchFrom}T00:00:00Z`))); if (searchTo) params.set('to', String(Date.parse(`${searchTo}T23:59:59.999Z`))); if (cursor) { params.set('before_created_at', String(cursor.before_created_at)); params.set('before_id', cursor.before_id); } return `/api/v1/messages/search?${params}`; }
  function searchMessages() { clearTimeout(messageSearchTimer); const term = messageSearch.trim(); if (!term) { searchResults = []; searchNext = null; return; } messageSearchTimer = setTimeout(async () => { try { const result = await request(searchUrl()); searchResults = result.body?.items ?? result.body ?? []; searchNext = result.body?.next ?? null; } catch { searchResults = []; searchNext = null; } }, 180); }
  async function loadMoreSearch() { if (!searchNext || !messageSearch.trim()) return; try { const result = await request(searchUrl(searchNext)); searchResults = [...searchResults, ...(result.body?.items ?? [])]; searchNext = result.body?.next ?? null; } catch { notice = 'Unable to load more search results'; } }

  async function loadAdmin() {
