    const assigned = user.roles.includes(role);
    try { await request(`/api/v1/admin/users/${user.id}/roles/${encodeURIComponent(role)}`, { method: assigned ? 'DELETE' : 'POST', headers: { 'x-csrf-token': csrf } }); await loadAdmin(); notice = `${user.username} ${assigned ? 'updated' : 'granted ' + role}`; } catch (error) { notice = error instanceof Error ? error.message : 'Role update failed'; }
  }

