    if (!password) return;
    try { await request(`/api/v1/admin/users/${user.id}/password-reset`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ password }) }); notice = `${user.username}'s password reset`; } catch (error) { notice = error instanceof Error ? error.message : 'Password reset failed'; }
