  async function moderateMessage(id: string, action: 'delete' | 'restore') { try { await request(`/api/v1/admin/messages/${id}/${action}`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ reason: 'Admin action' }) }); await loadAdmin(); notice = 'Message updated'; } catch (error) { notice = error instanceof Error ? error.message : 'Action failed'; } }
