  async function revokeBan(id: string) { try { await request(`/api/v1/admin/bans/${id}`, { method: 'DELETE', headers: { 'x-csrf-token': csrf } }); await loadAdmin(); notice = 'Ban revoked'; } catch (error) { notice = error instanceof Error ? error.message : 'Action failed'; } }
  async function updateAdminChannel(channel: AdminChannel) {
    const description = prompt(`Description for #${channel.name}`, channel.description) ?? channel.description;
    const retention = prompt(`Retention days for #${channel.name}`, String(channel.retention_days));
    if (retention === null) return;
    const retentionDays = Number.parseInt(retention, 10);
    if (!Number.isInteger(retentionDays) || retentionDays < 1 || retentionDays > 3650) { notice = 'Retention must be between 1 and 3650 days'; return; }
    try { await request(`/api/v1/admin/channels/${channel.id}`, { method: 'PATCH', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ description, retention_days: retentionDays }) }); await loadAdmin(); notice = 'Channel settings updated'; } catch (error) { notice = error instanceof Error ? error.message : 'Channel update failed'; }
  }

