  function wsUrl() { if (import.meta.env.VITE_WS_URL) return import.meta.env.VITE_WS_URL; const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:'; return `${protocol}//${location.host}/api/v1/ws`; }
  function connect() {
