    if (event.type === 'members' && event.channel === activeChannel) channelMembers = event.members ?? [];
    if (event.type === 'channel_created' && event.name) channels = sort([...channels, event.name]);
    if (event.type === 'channel_deleted' && event.name) { channels = channels.filter((item) => item !== event.name); if (activeChannel === event.name) join('main'); }
    if (event.type === 'joined' && event.name) { activeChannel = event.name; activeConversation = privateConversations.find((item) => item.name === event.name) ?? null; pendingChannel = null; messages = []; reactions = []; typingUsers = []; threadMessages = []; threadRoot = null; participants = []; channelMembers = []; editingId = null; historyHasMore = false; olderHistoryLoading = false; lastHistorySource = null; historyLoading = true; flushPendingMessages(event.name); void loadDraft(event.name); }
    if ((event.type === 'presence_sync' || event.type === 'participants') && event.channel === activeChannel) participants = event.participants ?? [];
    if (event.type === 'participant_joined' && event.channel === activeChannel && event.participant) participants = [...participants.filter((item) => item.user_id !== event.participant?.user_id), event.participant];
    if (event.type === 'participant_left' && event.channel === activeChannel && event.user_id) participants = participants.filter((item) => item.user_id !== event.user_id);
    if (event.type === 'history' && event.channel === activeChannel) { messages = event.messages ?? []; historyHasMore = Boolean(event.has_more); olderHistoryLoading = false; lastHistorySource = event.source ?? null; historyLoading = false; focusPermalink(); void scrollLatest(); }
    if (event.type === 'history_page' && event.channel === activeChannel) { const beforeHeight = viewport?.scrollHeight ?? 0; const older = event.messages ?? []; messages = [...older, ...messages.filter((message) => !older.some((item) => item.id === message.id))]; historyHasMore = Boolean(event.has_more); olderHistoryLoading = false; lastHistorySource = event.source ?? null; void tick().then(() => { if (viewport) viewport.scrollTop += viewport.scrollHeight - beforeHeight; }); }
    if (event.type === 'message' && event.message?.client_id) pendingMessages = pendingMessages.filter((item) => item.client_id !== event.message?.client_id);
    if (event.type === 'message' && event.message?.channel === activeChannel && !messages.some((item) => item.id === event.message?.id)) { const near = nearBottom(); messages = [...messages, event.message]; if (threadRoot && event.message.root_message_id === threadRoot) threadMessages = [...threadMessages, event.message]; void tick().then(() => { if (near) void scrollLatest(); }); }
    if (event.type === 'message_updated' && event.message) messages = messages.map((item) => item.id === event.message?.id ? event.message as Message : item);
    if (event.type === 'reaction_updated' && event.reaction) reactions = [...reactions.filter((item) => !(item.message_id === event.reaction?.message_id && item.emoji === event.reaction?.emoji)), event.reaction as ReactionSummary].filter((item) => item.user_ids.length > 0);
    if (event.type === 'thread_history' && event.messages) { threadRoot = String(event.root_message_id ?? ''); threadMessages = event.messages; }
    if (event.type === 'typing' && event.user_id && event.user_id !== authUser?.id) typingUsers = event.typing ? [...typingUsers.filter((item) => item.user_id !== event.user_id), { user_id: event.user_id, username: event.username ?? 'Someone' }] : typingUsers.filter((item) => item.user_id !== event.user_id);
    if (event.type === 'error') { const message = event.error ?? String(event.message ?? 'The server rejected that action'); if (message === 'session expired') { intentionalClose = true; clearInterval(heartbeatTimer); socket?.close(); authUser = null; notice = 'Your session expired. Sign in again.'; } else if (message === 'realtime connection interrupted') { clearInterval(heartbeatTimer); notice = 'Realtime connection interrupted. Replaying recent history…'; socket?.close(); } else notice = message; }
  }
  function sort(items: string[]) { return [...new Set(items)].sort((a, b) => a === 'main' ? -1 : b === 'main' ? 1 : a.localeCompare(b)); }
  function join(name: string) { if (name === activeChannel && !pendingChannel) return; clearTimeout(typingTimer); setTyping(false); void persistDraft(activeChannel, draft); if (send({ type: 'join_channel', name })) { pendingChannel = name; historyLoading = true; mobilePanel = null; } }
  function queueMessage(message: PendingMessage) { pendingMessages = [...pendingMessages.filter((item) => item.client_id !== message.client_id), message]; if (!send({ type: 'send_message', ...message })) { pendingMessages = pendingMessages.filter((item) => item.client_id !== message.client_id); return false; } return true; }
  function flushPendingMessages(channel: string) { for (const message of pendingMessages.filter((item) => item.channel === channel)) send({ type: 'send_message', ...message }); }
  function selectFile(event: globalThis.Event) { const input = event.currentTarget as HTMLInputElement; pendingFile = input.files?.[0] ?? null; }
  async function submit() {
    const text = draft.trim();
