    let fileIds: string[] = [];
    if (pendingFile) {
      uploading = true;
      try {
        const form = new FormData();
        form.append('file', pendingFile);
        const result = await request('/api/v1/files', { method: 'POST', body: form });
        fileIds = [(result.body as FileUpload).id];
      } catch (error) {
        notice = error instanceof Error ? error.message : 'File upload failed';
        uploading = false;
        return;
      }
      uploading = false;
    }
    if (queueMessage({ channel: activeChannel, text, file_ids: fileIds, client_id: crypto.randomUUID() })) {
      draft = '';
      pendingFile = null;
      void persistDraft(activeChannel, '');
    }
  }
  function setTyping(typing: boolean) { send({ type: 'typing', typing }); }
  function loadOlderHistory() { const oldest = messages[0]; if (!oldest || !historyHasMore || olderHistoryLoading || status !== 'connected') return; const requestedChannel = activeChannel; if (send({ type: 'load_history', channel: requestedChannel, before_created_at: oldest.created_at, before_id: oldest.id })) olderHistoryLoading = true; }
  function closeCreate() { createMode = null; newChannel = ''; userSearch = ''; userResults = []; }
  function create() { const name = newChannel.trim().toLowerCase(); if (name && send({ type: 'create_channel', name })) { closeCreate(); } }
  function createPrivate() { const name = newChannel.trim().toLowerCase(); if (name && send({ type: 'create_private_channel', name })) { closeCreate(); } }
  function openDirect(userId: string) { if (send({ type: 'open_direct', user_id: userId })) { pendingChannel = '__direct__'; closeCreate(); } }
  function searchForUsers() { clearTimeout(searchTimer); searchTimer = setTimeout(async () => { if (userSearch.trim().length < 1) { userResults = []; return; } try { const result = await request(`/api/v1/users/search?q=${encodeURIComponent(userSearch.trim())}`); userResults = result.body; } catch { userResults = []; } }, 180); }
  async function refreshMentionResults(value: string) { clearTimeout(mentionSearchTimer); const q = mentionQuery(value); if (q === null) { mentionResults = []; return; } mentionSearchTimer = setTimeout(async () => { try { const result = await request(`/api/v1/users/search?q=${encodeURIComponent(q)}`); const special = ['channel', 'here'].filter((name) => name.startsWith(q)).map((username) => ({ id: `special-${username}`, username })); if (draft === value) mentionResults = [...special, ...(result.body ?? [])]; } catch { if (draft === value) mentionResults = []; } }, 180); }
  async function refreshLinkPreviews(items: Message[]) {
    const urls = [...new Set(items.flatMap((item) => extractPreviewUrls(item.text)))].slice(0, 12);
    await Promise.all(urls.filter((url) => !linkPreviews[url] && !linkPreviewLoading.has(url)).map(async (url) => {
      linkPreviewLoading.add(url);
      try {
        const result = await request(`/api/v1/link-preview?url=${encodeURIComponent(url)}`);
        if (result.body?.title || result.body?.description || result.body?.image_url) linkPreviews = { ...linkPreviews, [url]: result.body };
      } catch { /* previews are optional and may be unavailable */ }
      finally { linkPreviewLoading.delete(url); }
    }));
  }
  function chooseMention(username: string) { draft = applyMention(draft, username); mentionResults = []; }
  function searchDirectory() { clearTimeout(directorySearchTimer); const term = filter.trim(); if (!term) { directoryUsers = []; return; } directorySearchTimer = setTimeout(async () => { try { const result = await request(`/api/v1/users/search?q=${encodeURIComponent(term)}`); directoryUsers = result.body; } catch { directoryUsers = []; } }, 180); }
  function openMemberDialog() { userSearch = ''; userResults = []; memberOpen = true; }
  async function inviteMember(userId: string) { try { await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ user_id: userId }) }); memberOpen = false; const result = await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members`); channelMembers = result.body; notice = 'Member invited'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to invite member'; } }
  async function createInviteLink() { try { const result = await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/invite-links`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ expires_at: Date.now() + 7 * 24 * 60 * 60 * 1000, max_uses: 0 }) }); inviteLink = `${location.origin}/invite/${result.body.token}`; await navigator.clipboard?.writeText(inviteLink); notice = 'Invite link copied'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to create invite link'; } }
  async function acceptInviteFromLocation() { const match = location.pathname.match(/^\/invite\/([a-fA-F0-9]{64})$/); if (!match) return; try { const result = await request(`/api/v1/invite-links/${match[1]}/accept`, { method: 'POST', headers: { 'x-csrf-token': csrf } }); history.replaceState({}, '', '/'); notice = `Joined ${result.body.name}`; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to accept invite link'; } }
  async function removeMember(userId: string) { try { await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members/${userId}`, { method: 'DELETE', headers: { 'x-csrf-token': csrf } }); channelMembers = channelMembers.filter((member) => member.user_id !== userId); notice = 'Member removed'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to remove member'; } }
  async function leaveConversation() { const name = activeChannel; try { await request(`/api/v1/channels/${encodeURIComponent(name)}/membership`, { method: 'DELETE', headers: { 'x-csrf-token': csrf } }); privateConversations = privateConversations.filter((conversation) => conversation.name !== name); join('main'); notice = 'Conversation left'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to leave conversation'; } }
  function removeChannel(name: string) { if (name !== 'main' && confirm(`Delete #${name}?`)) send({ type: 'delete_channel', name }); }
  function saveEdit() { const text = editDraft.trim(); if (editingId && text && send({ type: 'edit_message', id: editingId, text })) { editingId = null; editDraft = ''; } }
  function deleteMessage(id: string) { if (confirm('Delete this message?')) send({ type: 'delete_message', id }); }
  function toggleReaction(messageId: string, emoji: string) { const current = reactions.find((item) => item.message_id === messageId && item.emoji === emoji); const mine = current?.user_ids.includes(authUser?.id ?? ''); send({ type: mine ? 'remove_reaction' : 'add_reaction', message_id: messageId, emoji }); }
  function openThread(messageId: string) { threadMessages = []; threadRoot = messageId; send({ type: 'load_thread', message_id: messageId, before_created_at: null, before_id: null }); }
  function replyInThread() { if (threadRoot && draft.trim()) { const text = draft.trim(); if (queueMessage({ channel: activeChannel, text, file_ids: [], root_message_id: threadRoot, client_id: crypto.randomUUID() })) { draft = ''; void persistDraft(activeChannel, ''); } } }
  function markRead(message: Message) { send({ type: 'mark_read', message_id: message.id, created_at: message.created_at }); void loadUnread(); }
  function nearBottom() { return !viewport || viewport.scrollHeight - viewport.scrollTop - viewport.clientHeight < 120; }
  function scrollState() { showJump = !nearBottom(); if (viewport && viewport.scrollTop < 140) loadOlderHistory(); }
  async function scrollLatest() { await tick(); if (viewport) viewport.scrollTop = viewport.scrollHeight; showJump = false; }
  function time(value: number) { return new Date(value).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }

  onMount(() => { void bootstrap(); return () => { intentionalClose = true; clearTimeout(reconnectTimer); clearInterval(heartbeatTimer); socket?.close(); }; });
</script>

<svelte:head><title>vussa workspace</title><meta name="description" content="A focused realtime team workspace" /></svelte:head>

{#if !authUser}
  <main class="auth-layout"><section class="auth-panel"><div class="brand-mark">✦</div><p class="kicker">vussa workspace</p><h1>{authMode === 'login' ? 'Make space for better conversations.' : 'Create your workspace account.'}</h1><p class="auth-copy">A calm, focused place for teams to share ideas and keep work moving.</p><form onsubmit={(event) => { event.preventDefault(); void authenticate(); }}><label>Email or username<input bind:value={authEmail} placeholder="you@example.com" required /></label>{#if authMode === 'register'}<label>Username<input bind:value={authUsername} placeholder="your-handle" required /></label>{/if}<label>Password<input bind:value={authPassword} type="password" placeholder="Your password" required /></label><button class="primary-button" type="submit">{authMode === 'login' ? 'Sign in' : 'Create account'} <span>↗</span></button></form><button class="link-button" onclick={() => authMode = authMode === 'login' ? 'register' : 'login'}>{authMode === 'login' ? 'Need an account?' : 'Already have an account?'}</button>{#if notice}<p class="form-error">{notice}</p>{/if}</section><aside class="auth-art"><div class="art-orb orb-one"></div><div class="art-orb orb-two"></div><div class="art-card"><span class="status-dot"></span><strong>Live conversations</strong><span>Stay close to the work.</span></div></aside></main>
{:else}
  <main class="app-shell">
    {#if pushAvailable}<button class="push-button" onclick={() => void enablePush()} disabled={pushBusy} aria-label="Enable browser notifications">{pushEnabled ? '🔔' : '🔕'} Notifications</button>{/if}
    <header class="topbar"><button class="mobile-menu" aria-label="Open channels" onclick={() => mobilePanel = 'channels'}>☰</button><a class="brand" href="/" aria-label="vussa home"><span class="brand-mark small">✦</span><span><b>vussa</b><small>workspace</small></span></a><div class="topbar-center"><button class:active={activeView === 'chat'} onclick={() => activeView = 'chat'}>Chat</button>{#if isAdmin}<button class:active={activeView === 'admin'} onclick={() => activeView = 'admin'}>Admin</button>{/if}<button class:active={settingsOpen} onclick={() => { settingsOpen = true; void loadSettings(); }}>Settings</button></div><div class="topbar-actions"><span class="connection" class:online={status === 'connected'}><i></i>{status === 'connected' ? 'Live' : status === 'connecting' ? 'Connecting' : 'Offline'}</span><div class="account"><span class="avatar">{authUser.username.slice(0, 1).toUpperCase()}</span><span class="account-name">{authUser.username}</span><button aria-label="Sign out" onclick={() => void logout()}>↪</button></div></div></header>
    {#if notice}<div class="toast" role="status"><span>!</span>{notice}<button onclick={() => notice = ''} aria-label="Dismiss">×</button></div>{/if}
    {#if activeView === 'admin' && isAdmin}
      <section class="admin-shell"><aside class="admin-nav"><div><p class="kicker">Control room</p><h1>Administration</h1></div>{#each [['overview','Overview','⌂'],['users','Users','♙'],['roles','Roles & access','◈'],['channels','Channels','#'],['moderation','Moderation','⌁'],['reports','Reports','⚑'],['bans','Bans','⊘'],['participants','Participants','●'],['audit','Audit log','≡'],['operations','Operations','⌘']] as item}<button class:active={adminTab === item[0]} onclick={() => adminTab = item[0] as AdminTab}><span>{item[2]}</span>{item[1]}</button>{/each}</aside><section class="admin-content"><div class="section-heading"><div><p class="kicker">Workspace controls</p><h2>{adminTab[0].toUpperCase() + adminTab.slice(1)}</h2></div><span class="permission-badge">Authorized</span></div>{#if adminTab === 'overview'}<div class="metric-grid"><div><small>Active users</small><strong>{operations.active_users ?? '—'}</strong><span>currently enabled</span></div><div><small>WebSockets</small><strong>{operations.websockets ?? '—'}</strong><span>live connections</span></div><div><small>Outbox</small><strong>{operations.outbox_pending ?? '—'}</strong><span>pending events</span></div><div><small>Services</small><strong class="good">Healthy</strong><span>PostgreSQL · Valkey</span></div></div><div class="welcome-card"><span class="welcome-icon">✦</span><div><h3>Everything in one place.</h3><p>Use the sections on the left to manage accounts, access, channels, and operational health.</p></div></div>{:else if adminTab === 'users'}<div class="table-card"><div class="table-toolbar"><input placeholder="Search users" aria-label="Search users" /><span>{adminUsers.length} users</span></div><div class="table-scroll"><table><thead><tr><th>User</th><th>Role</th><th>Status</th><th></th></tr></thead><tbody>{#each adminUsers as user}<tr><td><strong>{user.username}</strong><small>{user.email}</small></td><td>{#each user.roles as role}<span class="role-pill">{role}</span>{/each}</td><td><span class:good={!user.disabled_at} class="state-pill">{user.disabled_at ? "Disabled" : "Active"}</span></td><td>{#if user.id !== authUser.id}<button class="row-action" onclick={() => void toggleUser(user)}>{user.disabled_at ? "Enable" : "Disable"}</button>{#each ["moderator", "admin"] as role}<button class="row-action" onclick={() => void toggleUserRole(user, role)}>{user.roles.includes(role) ? "Remove " + role : "Add " + role}</button>{/each}<button class="row-action" onclick={() => void invalidateUserSessions(user)}>Invalidate sessions</button><button class="row-action" onclick={() => void resetUserPassword(user)}>Reset password</button><button class="row-action" onclick={() => void deleteUser(user)}>Delete</button>{/if}</td></tr>{:else}<tr><td colspan="4" class="empty-cell">No users found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'roles'}<div class="table-card"><div class="table-toolbar"><span>Fixed roles and permissions</span></div><div class="table-scroll"><table><thead><tr><th>Role</th><th>Permissions</th></tr></thead><tbody>{#each adminRoles as role}<tr><td><strong>{role.role}</strong></td><td>{role.permissions.join(' · ') || 'No permissions assigned'}</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'audit'}<div class="table-card"><div class="table-toolbar"><span>Recent activity</span><span>{audit.length} events</span></div><div class="table-scroll"><table><thead><tr><th>Action</th><th>Target</th><th>Time</th></tr></thead><tbody>{#each audit as event}<tr><td><strong>{event.action}</strong></td><td>{event.target_type}</td><td>{new Date(event.created_at).toLocaleString()}</td></tr>{:else}<tr><td colspan="3" class="empty-cell">No audit activity yet.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'operations'}<div class="metric-grid compact">{#each Object.entries(operations) as pair}<div><small>{pair[0].replaceAll('_', ' ')}</small><strong>{pair[1]}</strong></div>{/each}</div>{:else if adminTab === "channels"}<div class="table-card"><div class="table-toolbar"><span>Workspace channels</span><span>{adminChannels.length} channels</span></div><div class="table-scroll"><table><thead><tr><th>Channel</th><th>Retention</th><th>State</th><th></th></tr></thead><tbody>{#each adminChannels as channel}<tr><td><strong>#{channel.name}</strong><small>{channel.description || "No description"}</small></td><td>{channel.retention_days} days</td><td><span class="state-pill">{channel.deleted_at ? "Deleted" : channel.archived_at ? "Archived" : "Active"}</span></td><td>{#if channel.name !== "main"}<button class="row-action" onclick={() => void toggleChannelPosting(channel)}>{channel.posting_restricted ? "Allow posting" : "Restrict posting"}</button><button class="row-action" onclick={() => void updateAdminChannel(channel)}>Edit settings</button>{#if channel.deleted_at}<button class="row-action" onclick={() => void setChannelState(channel.id, "undelete")}>Undelete</button>{:else}<button class="row-action" onclick={() => void setChannelState(channel.id, channel.archived_at ? "restore" : "archive")}>{channel.archived_at ? "Restore" : "Archive"}</button><button class="row-action" onclick={() => void setChannelState(channel.id, "delete")}>Delete</button>{/if}{/if}</td></tr>{:else}<tr><td colspan="4" class="empty-cell">No channels found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "moderation"}<div class="table-card"><div class="table-toolbar"><span>Message moderation</span><span>{adminMessages.length} messages</span></div><div class="table-scroll"><table><thead><tr><th>Message</th><th>Channel</th><th>Author</th><th>State</th><th></th></tr></thead><tbody>{#each adminMessages as message}<tr><td><strong>{message.text}</strong><small>{new Date(message.created_at).toLocaleString()}</small></td><td>#{message.channel}</td><td>{message.username}</td><td><span class="state-pill">{message.deleted_at ? "Deleted" : "Visible"}</span></td><td><button class="row-action" onclick={() => void moderateMessage(message.id, message.deleted_at ? "restore" : "delete")}>{message.deleted_at ? "Restore" : "Delete"}</button></td></tr>{:else}<tr><td colspan="5" class="empty-cell">No messages found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "reports"}<div class="table-card"><div class="table-toolbar"><span>Open message reports</span><span>{adminReports.length} reports</span></div><div class="table-scroll"><table><thead><tr><th>Message</th><th>Channel</th><th>Reporter</th><th>Reason</th><th></th></tr></thead><tbody>{#each adminReports as report}<tr><td><strong>{report.username}</strong><small>{report.text}</small></td><td>#{report.channel}</td><td>{report.reporter_user_id}</td><td>{report.reason}</td><td><button class="row-action" onclick={() => void updateReport(report.id, report.status === "resolved" ? "reopen" : "resolve")}>{report.status === "resolved" ? "Reopen" : "Resolve"}</button></td></tr>{:else}<tr><td colspan="5" class="empty-cell">No open reports.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "bans"}<div class="table-card"><div class="table-toolbar"><span>Active and historical bans</span><span>{adminBans.length} bans</span></div><div class="table-scroll"><table><thead><tr><th>User</th><th>Channel</th><th>Reason</th><th>Expires</th><th></th></tr></thead><tbody>{#each adminBans as ban}<tr><td><strong>{ban.username}</strong></td><td>{ban.channel ? "#" + ban.channel : "Workspace"}</td><td>{ban.reason}</td><td>{ban.expires_at ? new Date(ban.expires_at).toLocaleString() : "Never"}</td><td>{#if !ban.revoked_at}<button class="row-action" onclick={() => void revokeBan(ban.id)}>Revoke</button>{:else}<span class="state-pill">Revoked</span>{/if}</td></tr>{:else}<tr><td colspan="5" class="empty-cell">No bans found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "participants"}<div class="table-card"><div class="table-toolbar"><span>Online participants in #main</span><span>{adminParticipants.length} online</span></div><div class="table-scroll"><table><thead><tr><th>User</th><th>Role</th><th>Status</th></tr></thead><tbody>{#each adminParticipants as person}<tr><td><strong>{person.username}</strong></td><td>{person.roles.join(" · ") || "user"}</td><td><span class="state-pill good">Online</span></td></tr>{:else}<tr><td colspan="3" class="empty-cell">No online participants.</td></tr>{/each}</tbody></table></div></div>{/if}</section></section>
    {:else}
      <section class="workspace"><aside class="channel-sidebar" class:drawer-open={mobilePanel === 'channels'}><div class="sidebar-heading"><div><p class="kicker">Your workspace</p><h2>Channels <span>{channels.length}</span></h2></div><button class="icon-button" onclick={() => createMode = createMode === 'menu' ? null : 'menu'} aria-label="Create conversation">＋</button></div>{#if createMode}<div class="create-menu">{#if createMode === 'menu'}<p class="kicker">Create</p><button onclick={() => createMode = 'public'}><span class="create-symbol">#</span><span><strong>Public channel</strong><small>Everyone can find it</small></span></button><button onclick={() => createMode = 'private'}><span class="create-symbol">▣</span><span><strong>Private channel</strong><small>Invite members only</small></span></button><button onclick={() => { createMode = 'dm'; userSearch = ''; userResults = []; }}><span class="create-symbol">↗</span><span><strong>Direct message</strong><small>Start a private chat</small></span></button>{:else if createMode === 'public' || createMode === 'private'}<p class="kicker">{createMode === 'private' ? 'Private channel' : 'Public channel'}</p><input bind:value={newChannel} placeholder="channel-name" maxlength="40" onkeydown={(event) => event.key === 'Enter' && (createMode === 'private' ? createPrivate() : create())} /><div class="create-actions"><button class="secondary-button" onclick={() => createMode = 'menu'}>Back</button><button class="primary-button" onclick={() => createMode === 'private' ? createPrivate() : create()}>Create</button></div>{:else}<p class="kicker">Direct message</p><input bind:value={userSearch} oninput={searchForUsers} placeholder="Search people" aria-label="Search people" /><div class="user-results">{#each userResults as result}<button class="create-user" type="button" onclick={() => openDirect(result.id)}><span class="avatar">{result.username.slice(0, 1).toUpperCase()}</span><span>{result.username}</span></button>{:else}<small class="create-hint">Type a name to search.</small>{/each}</div><button class="secondary-button create-back" onclick={() => createMode = 'menu'}>Back</button>{/if}</div>{/if}<label class="search"><span>⌕</span><input bind:value={filter} oninput={searchDirectory} placeholder="Find a channel or person" aria-label="Find a channel or person" /></label><nav class="channel-list">{#each visibleChannels as channel}<div class="channel-row" class:active={channel === activeChannel}><button onclick={() => join(channel)}><span class="hash">#</span><span>{channel}</span>{#if unreadCounts[channel]}<b class="unread-badge">{unreadCounts[channel]}</b>{/if}</button>{#if channel !== 'main'}<button class="delete-channel" onclick={() => removeChannel(channel)} aria-label={`Delete ${channel}`}>×</button>{/if}</div>{:else}<p class="muted">No matching channels</p>{/each}</nav>{#if filter.trim() && directoryUsers.length}<div class="directory-results"><p class="kicker">People</p>{#each directoryUsers as person}<button class="directory-user" onclick={() => { openDirect(person.id); filter = ""; directoryUsers = []; }}><span class="avatar">{person.username.slice(0, 1).toUpperCase()}</span><span>{person.username}</span><small>Direct message</small></button>{/each}</div>{/if}<div class="private-section"><p class="kicker">Private conversations</p>{#each privateConversations as conversation}<div class="channel-row" class:active={conversation.name === activeChannel}><button onclick={() => join(conversation.name)}><span class="hash">{conversation.kind === "direct" ? "↗" : "▣"}</span><span>{conversation.display_name}</span></button></div>{:else}<p class="muted">No private conversations</p>{/each}</div><button class="mobile-close" onclick={() => mobilePanel = null}>Close</button></aside><section class="chat"><header class="chat-header"><div class="channel-heading"><span class="channel-icon">#</span><div><h2>{activeConversation?.display_name ?? activeChannel}</h2><p>{historyLoading ? 'Loading messages…' : activeConversation ? `${messages.length} messages · ${channelMembers.length} members` : `${messages.length} messages in this channel`}</p></div></div><button class="participant-toggle" onclick={() => mobilePanel = 'participants'}><span class="presence-ring"></span>{participants.length} online</button></header><div class="message-area" bind:this={viewport} onscroll={scrollState} role="log" aria-live="polite">{#if historyLoading}<div class="state"><div class="spinner"></div><p>Opening #{activeChannel}</p></div>{:else if messages.length === 0}<div class="state"><span class="state-icon">✦</span><h3>Start the conversation</h3><p>Be the first person to say something in #{activeChannel}.</p></div>{:else}<div class="messages">{#each messages as message (message.id)}<article class="message"><span class="avatar">{message.username.slice(0, 1).toUpperCase()}</span><div class="message-body"><div class="message-meta"><strong>{message.username}</strong><time>{time(message.created_at)}</time>{#if message.edited}<span>edited</span>{/if}</div>{#if editingId === message.id}<form class="edit-box" onsubmit={(event) => { event.preventDefault(); saveEdit(); }}><input bind:value={editDraft} aria-label="Edit message" maxlength="2000" /><button type="submit">Save</button><button type="button" onclick={() => editingId = null}>Cancel</button></form>{:else}<p>{@html renderSafeMarkdown(message.text)}</p>{#each extractPreviewUrls(message.text) as url}{#if linkPreviews[url]}<a class="link-preview" href={linkPreviews[url].url} target="_blank" rel="noreferrer" aria-label={`Open preview for ${url}`}>{#if linkPreviews[url].image_url}<img src={linkPreviews[url].image_url} alt="" loading="lazy" referrerpolicy="no-referrer" />{/if}<span><strong>{linkPreviews[url].title || url}</strong>{#if linkPreviews[url].description}<small>{linkPreviews[url].description}</small>{/if}</span></a>{/if}{/each}{#if reactions.filter((item) => item.message_id === message.id).length}<div class="reaction-list">{#each reactions.filter((item) => item.message_id === message.id) as reaction}<button onclick={() => toggleReaction(message.id, reaction.emoji)}>{reaction.emoji} {reaction.user_ids.length}</button>{/each}</div>{/if}<div class="message-actions" aria-label={`Actions for ${message.username}'s message`}><button onclick={() => toggleReaction(message.id, '👍')} aria-label="React with thumbs up">👍</button><button onclick={() => toggleReaction(message.id, '❤️')} aria-label="React with heart">❤️</button><button onclick={() => openThread(message.id)}>Thread</button><button onclick={() => markRead(message)}>Read</button><button onclick={() => void copyPermalink(message)}>Link</button><button onclick={() => void toggleSavedMessage(message)}>{savedMessageIds.has(message.id) ? 'Unsave' : 'Save'}</button><button onclick={() => void reportLatestMessage(message)}>Report</button>{#if message.username === authUser.username && !message.deleted}<button onclick={() => deleteMessage(message.id)}>Delete</button>{/if}{#if message.username === authUser.username}<button onclick={() => { editingId = message.id; editDraft = message.text; }}>Edit</button>{/if}</div>{/if}</div></article>{/each}</div>{/if}{#if showJump}<button class="jump" onclick={scrollLatest}>↓ Jump to latest</button>{/if}</div><form class="composer" onsubmit={(event) => { event.preventDefault(); void submit(); }}><div><input bind:value={draft} disabled={status !== 'connected' || historyLoading} maxlength="2000" placeholder={activeConversation ? `Message ${activeConversation.display_name}` : `Message #${activeChannel}`} aria-label="Message composer" /><span>{draft.length}/2000</span><label class="file-picker" title={pendingFile?.name ?? 'Attach a file'}>＋<input type="file" onchange={selectFile} /><span>{pendingFile?.name ?? 'Attach'}</span></label></div><button class="send" disabled={(!draft.trim() && !pendingFile) || status !== 'connected' || historyLoading || uploading} aria-label="Send message">↑</button></form></section><aside class="participant-sidebar" class:drawer-open={mobilePanel === 'participants'}><div class="sidebar-heading"><div><p class="kicker">Channel members</p><h2>Online <span>{participants.length}</span></h2></div><span class="presence-ring"></span></div>{#if activeConversation}<div class="member-list conversation-members"><p class="kicker">Members</p>{#each channelMembers as member}<div class="member"><span class="avatar">{member.username.slice(0, 1).toUpperCase()}</span><div><strong>{member.username}</strong><small>{member.membership_role}</small></div>{#if activeConversation.owner_user_id === authUser.id && member.membership_role !== "owner"}<button class="delete-channel" onclick={() => void removeMember(member.user_id)} aria-label={`Remove ${member.username}`}>×</button>{/if}</div>{/each}{#if activeConversation.owner_user_id === authUser.id}<button class="secondary-button private-action" onclick={openMemberDialog}>＋ Invite member</button><button class="secondary-button private-action" onclick={() => void createInviteLink()}>↗ Copy invite link</button>{:else}<button class="secondary-button private-action" onclick={() => void leaveConversation()}>Leave conversation</button>{/if}</div>{/if}<div class="member-list">{#each participants as person}<div class="member"><span class="avatar">{person.username.slice(0, 1).toUpperCase()}</span><div><strong>{participantDisplayName(person)}</strong><small>{participantSecondaryLabel(person)}</small></div><i></i></div>{:else}<p class="muted">No one is online yet.</p>{/each}</div><button class="mobile-close" onclick={() => mobilePanel = null}>Close</button></aside></section>
    {/if}
    <Dialog.Root bind:open={memberOpen}><Dialog.Portal><Dialog.Overlay class="dialog-overlay" /><Dialog.Content class="dialog"><Dialog.Title>Invite a member</Dialog.Title><Dialog.Description>Only invited users can access this private channel.</Dialog.Description><input bind:value={userSearch} oninput={searchForUsers} placeholder="Search by username" aria-label="Search members" /><div class="user-results">{#each userResults as result}<button class="row-action user-result" type="button" onclick={() => void inviteMember(result.id)}>{result.username}</button>{:else}<p class="muted">Search for a user to invite.</p>{/each}</div><div class="dialog-actions"><Dialog.Close class="secondary-button">Cancel</Dialog.Close></div></Dialog.Content></Dialog.Portal></Dialog.Root></main>{#if settingsOpen}<div class="dialog-overlay" role="presentation" onclick={(event) => event.target === event.currentTarget && (settingsOpen = false)}><div class="dialog settings-dialog" role="dialog" aria-modal="true" aria-labelledby="settings-title"><h2 id="settings-title">Workspace settings</h2><p>Update your profile and notification preferences.</p><form onsubmit={(event) => { event.preventDefault(); void saveSettings(); }}><label>Display name<input bind:value={profileDisplayName} maxlength="80" /></label><label>Custom status<input bind:value={profileStatus} maxlength="120" /></label><label>Status expiry<input type="datetime-local" value={profileStatusExpiry ? new Date(profileStatusExpiry).toISOString().slice(0, 16) : ''} onchange={(event) => profileStatusExpiry = event.currentTarget.value ? new Date(event.currentTarget.value).getTime() : null} /></label><fieldset><legend>Notifications</legend><label class="setting-check"><input type="checkbox" bind:checked={notificationPrefs.mentions} /> Mentions</label><label class="setting-check"><input type="checkbox" bind:checked={notificationPrefs.direct_messages} /> Direct messages</label><label class="setting-check"><input type="checkbox" bind:checked={notificationPrefs.channel_messages} /> Channel messages</label><label class="setting-check"><input type="checkbox" bind:checked={notificationPrefs.email_enabled} /> Email delivery</label><label class="setting-check"><input type="checkbox" bind:checked={notificationPrefs.browser_push_enabled} /> Browser push</label></fieldset><section class="account-tools"><h3>Account security</h3><div class="account-password"><input type="password" bind:value={currentPassword} placeholder="Current password" aria-label="Current password" /><input type="password" bind:value={newPassword} placeholder="New password" aria-label="New password" /><button type="button" class="secondary-button" onclick={() => void changePassword()} disabled={accountBusy || !currentPassword || !newPassword}>Change password</button></div><h3>Sessions</h3><div class="session-list">{#each accountSessions as accountSession}<div><span>{accountSession.current ? "Current session" : accountSession.id.slice(0, 8)}</span>{#if !accountSession.current}<button type="button" class="row-action" onclick={() => void revokeAccountSession(accountSession.id)} disabled={accountBusy}>Revoke</button>{/if}</div>{:else}<small>No other active sessions.</small>{/each}</div><div class="account-actions"><button type="button" class="secondary-button" onclick={() => void exportAccount()} disabled={accountBusy}>Export account</button><button type="button" class="row-action" onclick={() => void deleteAccount()} disabled={accountBusy}>Delete account</button></div></section><div class="dialog-actions"><button type="button" class="secondary-button" onclick={() => settingsOpen = false}>Cancel</button><button type="submit" class="primary-button">Save settings</button></div></form></div></div>{/if}
{/if}

{#if authUser && activeView === 'chat' && latestMessage}
  <aside class="message-tools" aria-label="Latest message tools">
    <div><strong>Latest message</strong><small>{latestMessage.username}</small></div>
    {#if latestMessage.file_ids?.length}
      <div class="attachment-list" aria-label="Message attachments">
        {#each latestMessage.file_ids as fileId}
          <a href={`/api/v1/files/${fileId}`} target="_blank" rel="noreferrer">Open attachment</a>
        {/each}
      </div>
    {/if}
    <div class="tool-actions">
      <button onclick={() => toggleReaction(latestMessage.id, '👍')} aria-label="React with thumbs up">👍</button>
      <button onclick={() => toggleReaction(latestMessage.id, '❤️')} aria-label="React with heart">❤️</button>
      <button onclick={() => openThread(latestMessage.id)} aria-label="Open thread">Thread</button>
      <button onclick={() => markRead(latestMessage)} aria-label="Mark latest message read">Read</button><button onclick={() => void copyPermalink(latestMessage)} aria-label="Copy message permalink">Link</button>
      <button onclick={() => void toggleSavedMessage(latestMessage)} aria-label={savedMessageIds.has(latestMessage.id) ? 'Unsave latest message' : 'Save latest message'}>{savedMessageIds.has(latestMessage.id) ? 'Unsave' : 'Save'}</button>
      <button onclick={() => void reportLatestMessage(latestMessage)} aria-label="Report latest message">Report</button>
      {#if latestMessage.username === authUser.username && !latestMessage.deleted}<button class="edit-link" onclick={() => { editingId = latestMessage.id; editDraft = latestMessage.text; }}>Edit</button>{/if}
      {#if latestMessage.username === authUser.username && !latestMessage.deleted}
        <button onclick={() => deleteMessage(latestMessage.id)} aria-label="Delete latest message">Delete</button>
      {/if}
    </div>
    <input bind:value={messageSearch} oninput={searchMessages} placeholder="Search messages" aria-label="Search messages" />
    <div class="search-filters" aria-label="Search filters"><select bind:value={searchChannel} onchange={searchMessages} aria-label="Search channel"><option value="">All channels</option>{#each channels as channel}<option value={channel}>#{channel}</option>{/each}</select><input type="date" bind:value={searchFrom} onchange={searchMessages} aria-label="Search from date" /><input type="date" bind:value={searchTo} onchange={searchMessages} aria-label="Search to date" /></div>
    {#if mentionResults.length}<div class="mention-results" aria-label="Mention suggestions">{#each mentionResults as person}<button onclick={() => chooseMention(person.username)}>@{person.username}</button>{/each}</div>{/if}
    {#if searchResults.length}<div class="search-results">{#each searchResults as result}<button onclick={() => join(result.message.channel)}><strong>#{result.message.channel}</strong> {@html safeSearchHighlight(result.highlighted || result.snippet)}</button>{/each}{#if searchNext}<button class="row-action" onclick={() => void loadMoreSearch()}>Load more results</button>{/if}</div>{/if}
    <button class="row-action" onclick={() => savedOpen = !savedOpen}>Saved messages ({savedMessages.length})</button>
    {#if savedOpen}<div class="saved-list">{#each savedMessages as saved}<button onclick={() => openSavedMessage(saved)}><strong>#{saved.channel}</strong> <span>{saved.text}</span></button>{:else}<small>No saved messages yet.</small>{/each}</div>{/if}
    <button class="row-action" onclick={() => favoritesOpen = !favoritesOpen}>Favorite channels ({favoriteChannels.length})</button>
    {#if favoritesOpen}<div class="saved-list">{#each favoriteChannels as favorite}<div><button onclick={() => { join(favorite); favoritesOpen = false; }}>#{favorite}</button><button class="row-action" onclick={() => void toggleFavorite(favorite)} aria-label={`Unfavorite ${favorite}`}>×</button></div>{:else}<small>No favorite channels yet.</small>{/each}</div>{/if}
    {#if threadRoot}
      <div class="thread-panel" aria-label="Message thread">
        <div class="thread-summary"><strong>Thread</strong><span>{threadMessages.length} replies</span><button onclick={() => threadRoot = null}>Close</button></div>
        <div class="thread-messages">{#each threadMessages as reply (reply.id)}<article><strong>{reply.username}</strong><time>{time(reply.created_at)}</time><p>{@html renderSafeMarkdown(reply.text)}</p></article>{:else}<small>No replies yet.</small>{/each}</div>
        <form class="thread-reply" onsubmit={(event) => { event.preventDefault(); replyInThread(); }}><input bind:value={draft} maxlength="2000" placeholder="Reply in thread" aria-label="Thread reply" /><button class="primary-button" type="submit" disabled={!draft.trim() || status !== 'connected'}>Reply</button></form>
      </div>
    {/if}
    {#if typingUsers.length}<small>{typingUsers.map((person) => person.username).join(', ')} typing…</small>{/if}
    {#if notifications.some((item) => !item.read_at)}
      <div class="notification-list"><strong>Notifications</strong>{#each notifications.filter((item) => !item.read_at).slice(0, 3) as notification}<button onclick={() => void readNotification(notification)}>{notification.body}</button>{/each}</div>
    {/if}
  </aside>
{/if}

<style>
  .push-button{position:fixed;z-index:15;top:76px;right:24px;border:1px solid #454069;border-radius:8px;padding:7px 10px;color:#dcd8ff;background:#26223e;font-size:11px}.push-button:disabled{opacity:.5}.message-actions{display:flex;flex-wrap:wrap;gap:5px;margin-top:8px;opacity:.72}.message-actions button{border:1px solid #34394a;border-radius:6px;padding:3px 6px;color:#9da5b8;background:#1a1d28;font-size:10px}.message-actions button:hover{color:#e3e5ef;border-color:#6659d9}.thread-panel{display:grid;gap:10px;margin-top:10px;padding:10px;border:1px solid #292e3c;border-radius:9px;background:#171a23}.thread-summary{display:flex;align-items:center;gap:8px;color:#858da0;font-size:11px}.thread-summary strong{color:#e1e4ed}.thread-summary button{margin-left:auto;border:0;color:#aaa2ff;background:none;font-size:11px}.thread-messages{display:grid;gap:8px;max-height:180px;overflow:auto}.thread-messages article{padding:7px;border-radius:7px;background:#10131a}.thread-messages strong{color:#dfe3ed;font-size:11px}.thread-messages time{margin-left:7px;color:#71798d;font-size:9px}.thread-messages p{margin:3px 0 0;color:#b8bfce;font-size:11px;line-height:1.4}.thread-reply{display:flex;gap:6px}.thread-reply input{min-width:0;flex:1;border:1px solid #3b4153;border-radius:7px;padding:8px;color:#fff;background:#10131a;font-size:11px}.thread-reply .primary-button{padding:8px 10px;font-size:10px}
